public DataSourceBuilder<?> initializeDataSourceBuilder() {
	return DataSourceBuilder.create(getClassLoader())
		.type(getType())
		.driverClassName(determineDriverClassName())
		.url(determineUrl())
		.username(determineUsername())
		.password(determinePassword());
}

