def sanitize_uri(uri: SplitResult) -> SplitResult:
    if not uri.netloc:
        raise ValueError("URI format vertica:// must contain a host")
    if uri.port is None:
        host = uri.netloc.rstrip(":")
        uri = uri._replace(netloc=f"{host}:5433")
    if len(uri.path.split("/")) != 4:  # Leading slash, database, schema, and table names.
        raise ValueError("URI format vertica:// must contain database, schema, and table names")
    return uri

